select ndgl.*, ndg.*, ds.*, da.*, grand.nx_distributer_father_goods_id 'grand_nx_distributer_father_goods_id', grand.nx_dfg_fathers_father_id 'grand_nx_dfg_fathers_father_id', grand.nx_dfg_father_goods_name 'grand_nx_dfg_father_goods_name', grand.nx_dfg_nx_goods_id 'grand_nx_dfg_nx_goods_id', grand.nx_dfg_father_goods_img 'grand_nx_dfg_father_goods_img', grand.nx_dfg_father_goods_sort 'grand_nx_dfg_father_goods_sort', greatGrand.nx_distributer_father_goods_id 'greatGrand_nx_dfg_distributer_father_goods_id', greatGrand.nx_dfg_distributer_id 'greatGrand.nx_dfg_distributer_id', greatGrand.nx_dfg_fathers_father_id 'greatGrand_nx_dfg_fathers_father_id', greatGrand.nx_dfg_father_goods_name 'greatGrand_nx_dfg_father_goods_name', greatGrand.nx_dfg_nx_goods_id 'greatGrand_nx_dfg_nx_goods_id', greatGrand.nx_dfg_father_goods_color 'greatGrand_nx_dfg_father_goods_color' from nx_distributer_goods_linshi as ndgl left join nx_distributer_goods as ndg on ndg.nx_distributer_goods_id = COALESCE(ndgl.nx_dg_to_nx_dis_goods_id, ndgl.nx_dg_from_nx_dis_goods_id) left join nx_distributer_standard as ds on ds.nx_DS_dis_goods_id = ndg.nx_distributer_goods_id left join nx_distributer_alias as da on da.nx_DA_dis_goods_id = ndg.nx_distributer_goods_id left join nx_distributer_father_goods as grand on grand.nx_distributer_father_goods_id = ndg.nx_dg_dfg_goods_grand_id left join nx_distributer_father_goods as greatGrand on greatGrand.nx_distributer_father_goods_id = grand.nx_dfg_fathers_father_id where ndgl.nx_dg_distributer_ls_id = #{disId}
and ndgl.nx_dg_goods_ls_status = #{status}
and ( ndgl.nx_dg_goods_ls_name like concat('%', #{searchGoodsName}, '%') or ndgl.nx_dg_goods_ls_standardname like concat('%', #{searchGoodsName}, '%') or ndg.nx_dg_goods_name like concat('%', #{searchGoodsName}, '%') or ndg.nx_dg_goods_standardname like concat('%', #{searchGoodsName}, '%')
or ndgl.nx_dg_goods_ls_pinyin like concat('%', #{searchPinyin}, '%') or ndgl.nx_dg_goods_ls_py like concat('%', #{searchPinyin}, '%') or ndg.nx_dg_goods_pinyin like concat('%', #{searchPinyin}, '%') or ndg.nx_dg_goods_py like concat('%', #{searchPinyin}, '%')
)
order by ndgl.nx_dg_apply_date desc, ndgl.nx_distributer_goods_ls_id desc
limit #{offset}, #{limit}

select count(*) from nx_distributer_goods_linshi as ndgl left join nx_distributer_goods as ndg on ndg.nx_distributer_goods_id = COALESCE(ndgl.nx_dg_to_nx_dis_goods_id, ndgl.nx_dg_from_nx_dis_goods_id) where ndgl.nx_dg_distributer_ls_id = #{disId}
and ndgl.nx_dg_goods_ls_status = #{status}
and ( ndgl.nx_dg_goods_ls_name like concat('%', #{searchGoodsName}, '%') or ndgl.nx_dg_goods_ls_standardname like concat('%', #{searchGoodsName}, '%') or ndg.nx_dg_goods_name like concat('%', #{searchGoodsName}, '%') or ndg.nx_dg_goods_standardname like concat('%', #{searchGoodsName}, '%')
or ndgl.nx_dg_goods_ls_pinyin like concat('%', #{searchPinyin}, '%') or ndgl.nx_dg_goods_ls_py like concat('%', #{searchPinyin}, '%') or ndg.nx_dg_goods_pinyin like concat('%', #{searchPinyin}, '%') or ndg.nx_dg_goods_py like concat('%', #{searchPinyin}, '%')
)

